# Calculate correlation matrix
correlation_matrix = df.drop(columns=['default']).corr().abs()

# Identify pairs of features with correlation above 0.85
high_correlation_pairs = []
for i in correlation_matrix.columns:
    for j in correlation_matrix.columns:
        if i != j and correlation_matrix.loc[i, j] > 0.85:
            high_correlation_pairs.append((i, j, correlation_matrix.loc[i, j]))

high_correlation_pairs = list(set([tuple(sorted(pair[:2])) + (pair[2],) for pair in high_correlation_pairs]))

print('Highly correlated feature pairs:', high_correlation_pairs)
